using System.Reflection;
using System.Reflection.Metadata;
using System.Reflection.PortableExecutable;

var dlls = new[] {
    "/home/runner/.nuget/packages/xunit.v3.common/3.1.0/lib/netstandard2.0/xunit.v3.common.dll",
    "/home/runner/.nuget/packages/xunit.v3.extensibility.core/3.1.0/lib/netstandard2.0/xunit.v3.core.dll",
};

foreach (var dllPath in dlls)
{
    Console.WriteLine($"\n--- {Path.GetFileName(dllPath)} ---");
    using var fs = File.OpenRead(dllPath);
    using var peReader = new PEReader(fs);
    var mdReader = peReader.GetMetadataReader();

    foreach (var tdHandle in mdReader.TypeDefinitions)
    {
        var td = mdReader.GetTypeDefinition(tdHandle);
        var name = mdReader.GetString(td.Name);
        var ns = mdReader.GetString(td.Namespace);
        if (name.Contains("TestCaseOrderer") || name.Contains("CollectionBehavior"))
        {
            Console.WriteLine($"Type: {ns}.{name}");
            // Check generic params
            var genericParams = td.GetGenericParameters();
            if (genericParams.Count > 0)
                Console.WriteLine($"  Generic params: {genericParams.Count}");

            // List methods
            foreach (var mh in td.GetMethods())
            {
                var method = mdReader.GetMethodDefinition(mh);
                var methodName = mdReader.GetString(method.Name);
                if (methodName == ".ctor")
                {
                    var sig = method.DecodeSignature(new SignatureTypeProvider(), null);
                    Console.WriteLine($"  Ctor({string.Join(", ", sig.ParameterTypes)})");
                }
            }

            // List properties
            foreach (var ph in td.GetProperties())
            {
                var prop = mdReader.GetPropertyDefinition(ph);
                Console.WriteLine($"  Prop: {mdReader.GetString(prop.Name)}");
            }
        }
    }
}

class SignatureTypeProvider : ISignatureTypeProvider<string, object?>
{
    public string GetPrimitiveType(PrimitiveTypeCode typeCode) => typeCode.ToString();
    public string GetTypeFromDefinition(MetadataReader reader, TypeDefinitionHandle handle, byte rawTypeKind)
    {
        var td = reader.GetTypeDefinition(handle);
        return reader.GetString(td.Namespace) + "." + reader.GetString(td.Name);
    }
    public string GetTypeFromReference(MetadataReader reader, TypeReferenceHandle handle, byte rawTypeKind)
    {
        var tr = reader.GetTypeReference(handle);
        return reader.GetString(tr.Namespace) + "." + reader.GetString(tr.Name);
    }
    public string GetSZArrayType(string elementType) => elementType + "[]";
    public string GetGenericInstantiation(string genericType, System.Collections.Immutable.ImmutableArray<string> typeArguments) 
        => genericType + "<" + string.Join(", ", typeArguments) + ">";
    public string GetArrayType(string elementType, ArrayShape shape) => elementType + "[]";
    public string GetByReferenceType(string elementType) => "ref " + elementType;
    public string GetPointerType(string elementType) => elementType + "*";
    public string GetFunctionPointerType(MethodSignature<string> signature) => "funcptr";
    public string GetGenericMethodParameter(object? genericContext, int index) => "!!" + index;
    public string GetGenericTypeParameter(object? genericContext, int index) => "!" + index;
    public string GetModifiedType(string modifier, string unmodifiedType, bool isRequired) => unmodifiedType;
    public string GetPinnedType(string elementType) => elementType;
    public string GetTypeFromSpecification(MetadataReader reader, object? genericContext, TypeSpecificationHandle handle, byte rawTypeKind) => "spec";
}
